local itemRecords = {
	types.Apparatus.records, types.Armor.records, types.Book.records,
	types.Clothing.records, types.Ingredient.records, types.Light.records,
	types.Lockpick.records, types.Miscellaneous.records, types.Potion.records,
	types.Probe.records, types.Repair.records, types.Weapon.records,
}

local function idExists(id)
	if leveled[id] then return true end
	for _, r in ipairs(itemRecords) do
		if r[id] then return true end
	end
	return false
end

for lid, entries in pairs(leveled) do
	for i = #entries, 1, -1 do
		if not idExists(entries[i]) then
			table.remove(entries, i)
		end
	end
	if #entries == 0 then leveled[lid] = nil end
end

return leveled